19	
20	/** @file*/
21	
22	#include "internal_nn_math.h"
23	#include "riscv_nn_support.h"
24	
25	//// Convolution Functions
26	int32_t riscv_nn_conv_HWC_s8_s16_s8_RGB_sym_bias_fast(const q7_t * in_tensor,
27	        const uint16_t in_tensor_dim,
28	        const q7_t * ker_weight,
29	        const uint16_t out_tensor_ch,
30	        const uint16_t ker_dim,
31	        const uint16_t pad,
32	        const uint16_t stride,
33	        const q31_t * bias,
34	        const uint16_t pre_rshift,
35	        const uint16_t out_scale,
36	        const uint16_t post_rshift,
37	        q15_t * out_tensor,
38	        const uint16_t out_tensor_dim,
39	        q15_t * in_tmp_buf,
40	        q15_t * wt_tmp_buf)
41	{
42	#ifdef ENA_EMPTY_FUN
43	    //empty body
44	#elif defined(ENA_VEC_ISA) && (ENA_VEC_INTRINSIC)
45	    long   i_out_y, i_out_x, i_ker_y, i_ker_x;
46	
47	    /*
48	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
49	     *  im2col are done to output in q15_t format from q7_t input
50	     */
51	    q7_t *pBuffer = (q7_t *)in_tmp_buf;
52	    q15_t *pOut = out_tensor;
53	
54	    long buf_len = (3 * ker_dim * ker_dim);
55	    long vl;
56	
57	    // This part implements the im2col function
58	    for (i_out_y = 0; i_out_y < out_tensor_dim; i_out_y++)
59	    {
60	        for (i_out_x = 0; i_out_x < out_tensor_dim; i_out_x++)
61	        {
62	            //init in_tmp_buf
63	            long len = buf_len;
64	            q7_t *pBuffer2 = pBuffer;
65	            vl = __riscv_vsetvl_e8m8(len);
66	            vint8m8_t vpBuffer2 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);   //zero
67	            while(len > 0)
68	            {
69	                __riscv_vse8(pBuffer2, vpBuffer2, vl);
70	                len -= vl;
71	                pBuffer2 += vl;
72	                vl = __riscv_vsetvl_e8m8(len);
73	            }
74	
75	            // if (i_ker_y < 0)
76	            for (i_ker_y = i_out_y * stride - pad; i_ker_y < 0; i_ker_y++)
77	            {
78	                pBuffer += ker_dim * 3;
79	            }
80	
81	            long bound_y = ((i_out_y * stride - pad + ker_dim) < in_tensor_dim) ? (i_out_y * stride - pad + ker_dim) : in_tensor_dim;
82	            for (; i_ker_y < bound_y; i_ker_y++)
83	            {
84	                // if (i_ker_x < 0)
85	                for (i_ker_x = i_out_x * stride - pad; i_ker_x < 0; i_ker_x++)
86	                {
87	                    pBuffer += 3;
88	                }
89	
90	                long bound_x = (i_out_x * stride - pad + ker_dim < in_tensor_dim) ? (i_out_x * stride - pad + ker_dim) : in_tensor_dim;
91	                const q7_t *pPixel = in_tensor + (i_ker_y * in_tensor_dim + i_ker_x) * 3;
92	                long loop = (bound_x - i_ker_x) * 3;
93	                i_ker_x = bound_x;
94	                while (loop > 0)
95	                {
96	                    vl = __riscv_vsetvl_e8m8(loop);
97	                    vint8m8_t vpPixel = __riscv_vle8_v_i8m8(pPixel, vl);
98	                    __riscv_vse8(pBuffer, vpPixel, vl);
99	                    pPixel += vl;
100	                    pBuffer += vl;
101	                    loop -= vl;
102	                }
103	
104	                // if (i_ker_x >= in_tensor_dim)
105	                for ( ; i_ker_x < i_out_x * stride - pad + ker_dim; i_ker_x++)
106	                {
107	                    pBuffer += 3;
108	                }
109	            }
110	
111	            // if (i_ker_y >= in_tensor_dim)
112	            for (; i_ker_y < i_out_y * stride - pad + ker_dim; i_ker_y++)
113	            {
114	                pBuffer += ker_dim * 3;
115	            }
116	
117	            if (pBuffer == (q7_t *)in_tmp_buf + 2 * (3 * ker_dim * ker_dim))
118	            {
119	                pOut = nn_mat_mul_kernel_q7_q15_bias_2sft((q7_t *)ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, 3 * ker_dim * ker_dim, pre_rshift, out_scale, post_rshift, bias, pOut);
120	                pBuffer = (q7_t *)in_tmp_buf;
121	            }
122	        }
123	    }
124	#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_NDS_V5_VEC_DOT_PROD)
125	    if (pBuffer != (q7_t *)in_tmp_buf)
126	    {
127	        unsigned vl;
128	        const q7_t *p_wt = ker_weight;
129	        int       i;
130	        uint16_t  colCnt = 3 * ker_dim * ker_dim;
131	        // long vlenb = NDS_VEC_CSR_GET_VLENB();
132	
133	        vl = __riscv_vsetvl_e32m1(1);
134	        vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0x0, vl);     //const zero for redsum
135	
136	        for (i = 0; i < out_tensor_ch; i++)
137	        {
138	            q7_t      *p_in = (q7_t*)in_tmp_buf;
139	            uint16_t colCnt2 = colCnt;
140	
141	            //clear v0~v7
142	            vl = __riscv_vsetvl_e32m8(colCnt);
143	            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
144	
145	            // while (colCnt2 >= (vlenb * NDS_VEC_VTYPE_LMUL_ID_M8))
146	            // {
147	            //     NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
148	            //     //load src1
149	            //     NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
150	            //     //load src2
151	            //     NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
152	            //     //bump pointers and update loop counter
153	            //     colCnt2 -= vl;
154	            //     p_wt += vl;
155	            //     p_in += vl;
156	            //     //set the proper avl/SEW/LMUL values for vd4dot
157	            //     vl >>= 2;
158	            //     NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
159	            //     //acc += src1 * src2
160	            //     NDS_VEC_VD4DOTS_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
161	            // }
162	
163	            //extra process for the case of elements to be dot producted is not a mutiple of 4
164	            while(colCnt2 > 0)
165	            {
166	                //clean one of the dot product source
167	                vl = __riscv_vsetvlmax_e8m8();
168	                vint8m8_t vP_wt_i8m8 = __riscv_vand(__riscv_vundefined_i8m8(), 0, vl);
169	
170	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
171	                vl = __riscv_vsetvl_e8m8(colCnt2);
172	                //load src1
173	                vP_wt_i8m8 = __riscv_vle8_v_i8m8_tu(vP_wt_i8m8, p_wt, vl);
174	                //load src2
175	                vint8m8_t vP_in_i8m8 = __riscv_vle8_v_i8m8(p_in, vl);
176	                //bump pointers and update loop counter
177	                colCnt2 -= vl;
178	                p_wt += vl;
179	                p_in += vl;
180	                //set the proper avl/SEW/LMUL values for vd4dot
181	                //remember to deal with the elements to be dot producted is not a multiple of 4 case
182	                vl = __riscv_vsetvl_e32m8(vl);
183	                //acc += src1 * src2
184	                vAccumulator = __riscv_vd4dots_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_i8m8, vl);
185	            }
186	
187	            vl = __riscv_vsetvl_e32m8(colCnt);  //note the avl here
188	            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
189	
190	            //add bias back
191	            vl = __riscv_vsetvl_e32m1(1);
192	            vint32m1_t vBias = __riscv_vle32_v_i32m1(bias, vl);
193	            vSum = __riscv_vadd(vSum, vBias, vl);
194	
195	            //2-stage shift
196	            vSum = __riscv_vsra(vSum, pre_rshift, vl);
197	            vSum = __riscv_vmul(vSum, out_scale, vl);
198	            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);
199	
200	            //scale down, clip and store the results
201	            vSum = __riscv_vsra(vSum, post_rshift, vl);
202	            vl = __riscv_vsetvl_e16mf2(1);
203	            vint16mf2_t vpOut = __riscv_vnclip(vSum, 0, __RISCV_VXRM_RNU, vl);
204	            __riscv_vse16(pOut, vpOut, vl);
205	            bias += vl;
206	            pOut += vl;
207	        }
208	    }
209	#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_ISA_ZVQMAC)
210	    /* left-over because odd number of output pixels */
211	    if (pBuffer != (q7_t *)in_tmp_buf)
212	    {
213	        const q7_t *pA = ker_weight;
214	        long i;
215	        /* basically each time it process 4 entries */
216	        long colCnt = (3 * ker_dim * ker_dim);
217	
218	        //set SEW for 1st time VMV_S_X
219	        //LMUL=8 is just for clear v8~v15 (vmv ignores LMUL)
220	        vl = __riscv_vsetvl_e32m8(colCnt);
221	
222	        for (i = 0; i < out_tensor_ch; i++)
223	        {
224	            q31_t sum = bias[i];
225	            q7_t *pB = (q7_t*)in_tmp_buf;
226	            long colCnt2 = colCnt;
227	
228	            //init
229	            vint32m1_t vSum = __riscv_vmv_s_x_i32m1(sum, 1);
230	            //clear v8~v15 (acc)
231	            vint32m8_t vAcc = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
232	
233	            while(colCnt2 > 0)
234	            {
235	                vl = __riscv_vsetvl_e8m2(colCnt2);
236	                vint8m2_t vpA = __riscv_vle8_v_i8m2(pA, vl);
237	                vint8m2_t vpB = __riscv_vle8_v_i8m2(pB, vl);
238	                vAcc = __riscv_vqmacc(vAcc, vpA, vpB, vl);
239	                //bump pointers and update loop counter
240	                colCnt2 -= vl;
241	                pA += vl;
242	                pB += vl;
243	            }
244	
245	            vl = __riscv_vsetvl_e32m8(colCnt);
246	            vSum = __riscv_vredsum_tu(vSum, vAcc, vSum, vl);
247	            //move vr results to gpr
248	            sum = __riscv_vmv_x(vSum);
249	
250	            sum  = (sum  >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
251	            *pOut++ = NDS_ISA_SATS((sum >> post_rshift), 16);
252	        }
253	    }
254	#endif
255	#elif defined(ENA_VEC_ISA)
256	#if defined(ENA_TILING)
257	#if (NDS_VEC_RVV_VERSION >= 1000)
258	    /*
259	     * Direct convolution with fused bias + requantize.
260	     * Vectorizes across out_tensor_ch: vqmacc.vx accumulates one input scalar
261	     * against the full transposed weight row (all output channels).
262	     * Processes 4 output pixels at a time, sharing weight loads.
263	     * Eliminates im2col buffer and q32 intermediate buffer.
264	     *
265	     * Output is q15_t (16-bit), so requantization narrows only once
266	     * from e32 to e16 (no second narrowing to e8).
267	     *
268	     * Register plan:
269	     *   v0-v3   (M4 e32): Accumulator pixel 1
270	     *   v4-v7   (M4 e32): Accumulator pixel 2
271	     *   v8-v11  (M4 e32): Accumulator pixel 3
272	     *   v12-v15 (M4 e32): Accumulator pixel 4
273	     *   v16     (M1 e8):  Weight vector load
274	     */
275	    const int in_tensor_ch = 3;
276	    long i_ker_y, i_ker_x, ch;
277	
278	    const long align_byte = 64;
279	    q15_t *pOut = out_tensor;
280	    long vl;
281	
282	    /* Allocate transposed weight buffer from in_tmp_buf */
283	    q7_t *src2 = (q7_t *)in_tmp_buf;
284	    src2 = (q7_t*)nn_align((unsigned long)src2, align_byte);
285	
286	    /* Transpose weights once: from [out_ch x K] to [K x out_ch] */
287	    const long row = out_tensor_ch;
288	    const long col = ker_dim * ker_dim * in_tensor_ch;
289	    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, src2, row, col);
290	
291	    /* Total output pixels */
292	    long total_pixels = (long)out_tensor_dim * out_tensor_dim;
293	    long pixel_idx = 0;
294	
295	    /* Process 4 output pixels at a time */
296	    for (; pixel_idx + 3 < total_pixels; pixel_idx += 4)
297	    {
298	        long out_y1 = pixel_idx / out_tensor_dim;
299	        long out_x1 = pixel_idx % out_tensor_dim;
300	        long out_y2 = (pixel_idx + 1) / out_tensor_dim;
301	        long out_x2 = (pixel_idx + 1) % out_tensor_dim;
302	        long out_y3 = (pixel_idx + 2) / out_tensor_dim;
303	        long out_x3 = (pixel_idx + 2) % out_tensor_dim;
304	        long out_y4 = (pixel_idx + 3) / out_tensor_dim;
305	        long out_x4 = (pixel_idx + 3) % out_tensor_dim;
306	
307	        /* Channel-striping loop: process out_tensor_ch in VLMAX-sized chunks */
308	        long ch_off = 0;
309	        while (ch_off < out_tensor_ch)
310	        {
311	            long ch_remain = out_tensor_ch - ch_off;
312	
313	            /* Load bias into 4 M4 accumulators at e32/M4 */
314	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
315	            NDS_VEC_VLE32_V(NDS_VEC_V0, bias + ch_off);
316	            NDS_VEC_VLE32_V(NDS_VEC_V4, bias + ch_off);
317	            NDS_VEC_VLE32_V(NDS_VEC_V8, bias + ch_off);
318	            NDS_VEC_VLE32_V(NDS_VEC_V12, bias + ch_off);
319	
320	            /* Set e8/M1 once for all vqmacc accumulation (e8*e8->e32, M1 input, M4 acc) */
321	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M1);
322	
323	            /* Accumulate over all K positions */
324	            if (pad == 0)
325	            {
326	                /* Fast path: no padding means all pixels are interior -- skip boundary checks */
327	                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
328	                {
329	                    long in_row1 = out_y1 * stride + i_ker_y;
330	                    long in_row2 = out_y2 * stride + i_ker_y;
331	                    long in_row3 = out_y3 * stride + i_ker_y;
332	                    long in_row4 = out_y4 * stride + i_ker_y;
333	
334	                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
335	                    {
336	                        long in_col1 = out_x1 * stride + i_ker_x;
337	                        long in_col2 = out_x2 * stride + i_ker_x;
338	                        long in_col3 = out_x3 * stride + i_ker_x;
339	                        long in_col4 = out_x4 * stride + i_ker_x;
340	                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
341	
342	                        for (ch = 0; ch < in_tensor_ch; ch++)
343	                        {
344	                            long k_pos = k_base + ch;
345	
346	                            /* Load transposed weight row into v16 at e8/M1 */
347	                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
348	
349	                            /* Get input scalars -- no boundary checks needed */
350	                            q7_t a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
351	                            q7_t a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
352	                            q7_t a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
353	                            q7_t a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
354	
355	                            /* vqmacc.vx: acc[e32/M4] += scalar * wt[e8/M1] */
356	                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
357	                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
358	                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
359	                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
360	                        }
361	                    }
362	                }
363	            }
364	            else
365	            {
366	                /* General path: check boundaries for padding */
367	                for (i_ker_y = 0; i_ker_y < ker_dim; i_ker_y++)
368	                {
369	                    long in_row1 = out_y1 * stride - pad + i_ker_y;
370	                    long in_row2 = out_y2 * stride - pad + i_ker_y;
371	                    long in_row3 = out_y3 * stride - pad + i_ker_y;
372	                    long in_row4 = out_y4 * stride - pad + i_ker_y;
373	
374	                    for (i_ker_x = 0; i_ker_x < ker_dim; i_ker_x++)
375	                    {
376	                        long in_col1 = out_x1 * stride - pad + i_ker_x;
377	                        long in_col2 = out_x2 * stride - pad + i_ker_x;
378	                        long in_col3 = out_x3 * stride - pad + i_ker_x;
379	                        long in_col4 = out_x4 * stride - pad + i_ker_x;
380	                        long k_base = (i_ker_y * ker_dim + i_ker_x) * in_tensor_ch;
381	
382	                        for (ch = 0; ch < in_tensor_ch; ch++)
383	                        {
384	                            long k_pos = k_base + ch;
385	
386	                            /* Load transposed weight row into v16 at e8/M1 */
387	                            NDS_VEC_VLB_V(NDS_VEC_V16, src2 + k_pos * out_tensor_ch + ch_off);
388	
389	                            /* Get input scalars with boundary checks */
390	                            q7_t a1 = 0, a2 = 0, a3 = 0, a4 = 0;
391	                            if (in_row1 >= 0 && in_row1 < in_tensor_dim &&
392	                                in_col1 >= 0 && in_col1 < in_tensor_dim)
393	                                a1 = in_tensor[(in_row1 * in_tensor_dim + in_col1) * in_tensor_ch + ch];
394	                            if (in_row2 >= 0 && in_row2 < in_tensor_dim &&
395	                                in_col2 >= 0 && in_col2 < in_tensor_dim)
396	                                a2 = in_tensor[(in_row2 * in_tensor_dim + in_col2) * in_tensor_ch + ch];
397	                            if (in_row3 >= 0 && in_row3 < in_tensor_dim &&
398	                                in_col3 >= 0 && in_col3 < in_tensor_dim)
399	                                a3 = in_tensor[(in_row3 * in_tensor_dim + in_col3) * in_tensor_ch + ch];
400	                            if (in_row4 >= 0 && in_row4 < in_tensor_dim &&
401	                                in_col4 >= 0 && in_col4 < in_tensor_dim)
402	                                a4 = in_tensor[(in_row4 * in_tensor_dim + in_col4) * in_tensor_ch + ch];
403	
404	                            /* vqmacc.vx: acc[e32/M4] += scalar * wt[e8/M1] */
405	                            NDS_VEC_VQMACC_VX(NDS_VEC_V0, a1, NDS_VEC_V16);
406	                            NDS_VEC_VQMACC_VX(NDS_VEC_V4, a2, NDS_VEC_V16);
407	                            NDS_VEC_VQMACC_VX(NDS_VEC_V8, a3, NDS_VEC_V16);
408	                            NDS_VEC_VQMACC_VX(NDS_VEC_V12, a4, NDS_VEC_V16);
409	                        }
410	                    }
411	                }
412	            }
413	
414	            /* Requantize pixel 1: shift, scale, narrow e32->e16, store halfword */
415	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
416	            NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
417	            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
418	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E16, NDS_VEC_VTYPE_LMUL_M2);
419	            NDS_VEC_VNCLIP_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
420	            NDS_VEC_VSH_V(NDS_VEC_V0, pOut + ch_off);
421	
422	            /* Requantize pixel 2 */
423	            NDS_VEC_VSETVLI(vl, ch_remain, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M4);
