807	                pBuffer = in_tmp_buf;
808	            }
809	        }
810	    }
811	
812	    if (pBuffer != in_tmp_buf)
813	    {
814	        const q7_t *pA = ker_weight;
815	        int i;
816	
817	        for (i = 0; i < out_tensor_ch; i++)
818	        {
819	            q31_t   sum = bias[i];
820	            q15_t   *pB = in_tmp_buf;
821	
822	            /* basically each time it process 4 entries */
823	            uint16_t  colCnt = 3 * ker_dim * ker_dim >> 2;
824	
825	            while (colCnt)
826	            {
827	                q31_t     inA1, inA2;
828	                q31_t     inB1, inB2;
829	
830	                pA = (q7_t *) read_and_pad((void *)pA, &inA1, &inA2);
831	                inB1 = *__SIMD32(pB)++;
832	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
833	                inB2 = *__SIMD32(pB)++;
834	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
835	
836	                colCnt--;
